import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { useTheme } from '../contexts/ThemeContext';
import { ArrowLeft, Sun, Moon, LogOut, User, ChevronRight, Shield } from 'lucide-react';

export default function SettingsPage() {
  const navigate = useNavigate();
  const { user, logout } = useAuth();
  const { theme, toggleTheme } = useTheme();
  const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <div className="min-h-screen bg-[#0A0A0A] dark:bg-[#0A0A0A]">
      {/* Header */}
      <header className="bg-[#141414] border-b border-[#27272A]/40 sticky top-0 z-50">
        <div className="max-w-2xl mx-auto px-4 py-4 flex items-center gap-4">
          <button
            onClick={() => navigate('/')}
            className="text-[#A1A1AA] hover:text-white hover:bg-[#1A1A1A] p-2 rounded-md transition-colors"
          >
            <ArrowLeft className="w-5 h-5" />
          </button>
          <h1 className="barlow text-2xl font-black tracking-tighter text-white">Settings</h1>
        </div>
      </header>

      <main className="max-w-2xl mx-auto px-4 py-8 space-y-6">

        {/* Profile card */}
        <div className="bg-[#1A1A1A] border border-[#27272A] rounded-md p-6 flex items-center gap-4">
          <div className="w-14 h-14 rounded-full bg-[#007AFF] flex items-center justify-center flex-shrink-0">
            <span className="barlow text-2xl font-black text-white">
              {user?.name?.charAt(0).toUpperCase()}
            </span>
          </div>
          <div>
            <p className="barlow text-xl font-bold text-white">{user?.name}</p>
            <p className="text-[#71717A] text-sm">{user?.email}</p>
            {user?.gym_id && (
              <p className="text-[#007AFF] text-xs uppercase tracking-widest mt-1">Gym Member</p>
            )}
          </div>
        </div>

        {/* Appearance */}
        <div>
          <p className="text-[#71717A] text-xs uppercase tracking-widest font-bold mb-3 px-1">Appearance</p>
          <div className="bg-[#1A1A1A] border border-[#27272A] rounded-md overflow-hidden">
            <div className="flex items-center justify-between px-6 py-4">
              <div className="flex items-center gap-3">
                {theme === 'dark'
                  ? <Moon className="w-5 h-5 text-[#A1A1AA]" />
                  : <Sun className="w-5 h-5 text-[#FF9F0A]" />
                }
                <div>
                  <p className="text-white font-medium">Theme</p>
                  <p className="text-[#71717A] text-sm capitalize">{theme} mode</p>
                </div>
              </div>
              {/* Toggle switch */}
              <button
                onClick={toggleTheme}
                className={`relative w-14 h-7 rounded-full transition-colors duration-300 focus:outline-none ${
                  theme === 'light' ? 'bg-[#007AFF]' : 'bg-[#27272A]'
                }`}
              >
                <span className={`absolute top-1 w-5 h-5 bg-white rounded-full shadow transition-transform duration-300 ${
                  theme === 'light' ? 'translate-x-8' : 'translate-x-1'
                }`} />
              </button>
            </div>
          </div>
        </div>

        {/* Account */}
        <div>
          <p className="text-[#71717A] text-xs uppercase tracking-widest font-bold mb-3 px-1">Account</p>
          <div className="bg-[#1A1A1A] border border-[#27272A] rounded-md overflow-hidden divide-y divide-[#27272A]">
            <div className="flex items-center justify-between px-6 py-4">
              <div className="flex items-center gap-3">
                <Shield className="w-5 h-5 text-[#34C759]" />
                <div>
                  <p className="text-white font-medium">Email Verification</p>
                  <p className="text-[#71717A] text-sm">Your email is verified</p>
                </div>
              </div>
              <span className="text-[#34C759] text-xs font-bold uppercase tracking-widest">Active</span>
            </div>
          </div>
        </div>

        {/* Danger zone */}
        <div>
          <p className="text-[#71717A] text-xs uppercase tracking-widest font-bold mb-3 px-1">Account Actions</p>
          <div className="bg-[#1A1A1A] border border-[#27272A] rounded-md overflow-hidden">
            {!showLogoutConfirm ? (
              <button
                onClick={() => setShowLogoutConfirm(true)}
                className="w-full flex items-center justify-between px-6 py-4 hover:bg-[#27272A]/50 transition-colors"
              >
                <div className="flex items-center gap-3">
                  <LogOut className="w-5 h-5 text-[#FF3B30]" />
                  <p className="text-[#FF3B30] font-medium">Log Out</p>
                </div>
                <ChevronRight className="w-4 h-4 text-[#71717A]" />
              </button>
            ) : (
              <div className="px-6 py-5">
                <p className="text-white font-medium mb-1">Are you sure you want to log out?</p>
                <p className="text-[#71717A] text-sm mb-4">You'll need to log back in to access your account.</p>
                <div className="flex gap-3">
                  <button
                    onClick={handleLogout}
                    className="flex-1 bg-[#FF3B30] hover:bg-[#CC2F26] text-white font-bold py-2 rounded-md transition-colors text-sm"
                  >
                    Yes, log out
                  </button>
                  <button
                    onClick={() => setShowLogoutConfirm(false)}
                    className="flex-1 bg-[#27272A] hover:bg-[#3f3f46] text-white font-bold py-2 rounded-md transition-colors text-sm"
                  >
                    Cancel
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>

      </main>
    </div>
  );
}
